{
  "title": "Kursus Membina Rumah: Panduan Lengkap",
  "description": "Kursus ini direka untuk memberikan pengetahuan dan kemahiran asas dalam membina rumah, dengan fokus kepada bahan, proses, dan tujuan membantu orang lain.",
  "modules": [
    {
      "id": "module_1",
      "title": "Pengenalan kepada Bahan Pembinaan",
      "description": "Menggali pelbagai jenis bahan yang biasa digunakan dalam pembinaan rumah, termasuk kayu, batu, dan konkrit. Aktiviti: Senaraikan bahan yang anda ketahui dan bincangkan penggunaannya."
    },
    {
      "id": "module_2",
      "title": "Perancangan dan Persediaan",
      "description": "Langkah-langkah awal yang perlu diambil sebelum memulakan pembinaan, termasuk pemilihan lokasi dan mendapatkan kebenaran. Aktiviti: Buat pelan ringkas lokasi rumah yang ingin dibina."
    },
    {
      "id": "module_3",
      "title": "Proses Pembinaan",
      "description": "Langkah demi langkah dalam proses pembinaan rumah, dari asas hingga siap. Aktiviti: Diskusikan peranan setiap langkah dalam pembinaan dan bagaimana ia membantu orang lain."
    },
    {
      "id": "module_4",
      "title": "Penyelesaian dan Penilaian",
      "description": "Menilai hasil akhir dan memastikan rumah memenuhi keperluan. Aktiviti: Buat senarai semak untuk menilai rumah yang telah dibina."
    }
  ]
}
